var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇군요. 서윤 양이 당했다고요?","JPN":"そうですか。シズカさんがやられたと。","ENG":"I see. Seo Yoon got caught, you say?","TWN":"原來如此，徐芸遭遇了襲擊？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"네, 소실됐던 침식파가 순식간에 폭증하면서 통신도 끊어졌어요.","JPN":"はい、消失していた侵食波が一瞬で急増し、通信も途切れました。","ENG":"Yes, the dormant Corruption ray suddenly spiked, and communications were cut off.","TWN":"是的，消失的侵蝕波突然激增，同時通訊也被切斷了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"현재는 준 3종급으로 관측되지만… 침식파를 일시적으로 숨겼던 걸 감안하면, 그 이상일지도 모릅니다.","JPN":"現在は準3種レベルに見えますが……侵食波を一時的に隠したことを考えると、それ以上かもしれません。","ENG":"It's currently being observed as a near Category 3... But considering the Corruption ray was temporarily hidden, it might be even worse.","TWN":"目前探測到的侵蝕等級為3類……但考慮到她曾暫時隱藏了侵蝕波，恐怕實際等級更高。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우리가 그 작은 불씨를 너무 오랫동안 방치해둔 모양이군요.","JPN":"私たちは小さい火種を長く放置しすぎたようですね。","ENG":"We've let that small spark smolder for too long.","TWN":"看來，我們放任她太久了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"흔한 침식사태 중 하나인 줄 알았더니, 일이 이 정도로 커질 줄이야.","JPN":"よくある侵食事態の1つだと思ったのに、ここまで事が大きくなるとは。","ENG":"I thought it was just a typical Corruption disaster, but I didn't expect it to escalate this much.","TWN":"本以為只是普通的侵蝕事件，沒想到事態會發展到如此地步。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"부사장님이 나서진 않는 건가요?","JPN":"副社長は動かないんですか？","ENG":"Aren't you going to step in, Vice President?","TWN":"副總你不出面嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"관리국 프로필엔 규격 외의 S급 카운터로 등록돼 있던데요.","JPN":"管理局のプロフィールには規格外のS級カウンター、と登録されていましたが。","ENG":"I saw that the profile in the Administration lists her as a Grade S Counter far exceeding the standard.","TWN":"管理局的檔案裡，她已經登記為超規格的S級制裁者。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"전 관리국 감찰과 해외지부 업무로 두 발이 묶인 몸입니다.","JPN":"私は管理局の監察と海外支部の仕事で身動きが取れない状態です。","ENG":"I'm tied up with the Administration's inspections and overseas branch duties.","TWN":"我現在被管理局監察科和海外分部的事務纏住，無法脫身。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"게다가 서윤 양도 아직 살아 있다면서요? 의뢰를 맡았으니 본인이 끝까지 책임을 지고 마무리 할 겁니다.","JPN":"そしてシズカさんもまだ生きていますよね？　一度受けた依頼ですから、本人が最後まで責任をもって終わらせるはずです。","ENG":"And, isn't Seo Yoon still alive? Since she took on the request, she'll make sure to see it through to the end.","TWN":"而且徐芸還活著，不是嗎？既然接下了任務，她肯定會負責到底，完成任務。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"혹시 두 분의 관계가 원수지간인가요?","JPN":"もしかしてお二人って犬猿の仲ですか？","ENG":"Are you two mortal enemies, by any chance?","TWN":"你們兩位是有什麼過節嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"상사와 부하 직원의 관계. 딱 그 정도 선을 지키며 서로를 존중해주는 거죠.","JPN":"同じ会社の上司と部下。ちょうとそのくらいの線を守りながらお互いを尊重するだけです。","ENG":"We're in a boss-employee relationship. We respect each other while keeping things professional.","TWN":"只是上司和部下的關係，僅此而已。我們彼此保持適當的距離，相互尊重。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 직원은 자존심이 아주 강해서 아무 손이나 빌려 쓰지 않는 타입이거든요.","JPN":"あの人はプライドが高すぎますので、誰にでも助けを求めるようなタイプではないんです。","ENG":"That employee has a strong sense of pride and doesn't ask just anyone for help.","TWN":"她是個自尊心極強的人，不會隨便借別人的手去完成工作。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아무리 그래도, 자존심 때문에 목숨을 포기하진 않을 텐데요…?","JPN":"いくら何でも、プライドのために自分の命を諦めたりはしないと思いますが……？","ENG":"Even so, she wouldn't just give up her life because of pride...?","TWN":"但就算如此，也不至於因為自尊心而放棄性命吧？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇게 보여도 어쩔 수 없죠. 이건 목숨과 비용을 저울질하는 비즈니스니까요.","JPN":"そう見えても仕方ありません。これは命とコストを天秤にかけるビジネスですから。","ENG":"Even if it seems that way, there's nothing to be done. This is a business where life and costs are weighed against each other.","TWN":"即便如此，也沒有辦法。這歸根結底是要在生命和成本之間進行衡量的商業決策。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"박사님은 맡은 역할에 충실하세요. 대원의 사망이 확인되기 전까지 추가 투입은 없습니다.","JPN":"博士はご自身の役割を果たしてください。隊員の死亡が確認されるまで増員はありません。","ENG":"Doctor, just focus on your role. There will be no additional deployment until the death of a member is confirmed.","TWN":"博士你只要做好自己的本份就好。在確認隊員死亡之前，我們不會提供額外的支援。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그럼-","JPN":"ではー","ENG":"Well then.","TWN":"那麼，先走一步。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"선배, 직장 생활이란 거… 쉽지 않네요.","JPN":"先輩、社会人って……難しいですね。","ENG":"Work life is... tougher than I expected.","TWN":"前輩，職場生活……果然不容易呢。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"난 현장엔 절대 나가지 말아야지.","JPN":"私は絶対に現場には出ないようにしよう。","ENG":"I'm never going out into the field.","TWN":"我可絕對不會去現場工作的。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"도시관리국이 그라운드 원의 전 태스크포스에 전파합니다.","JPN":"都市管理局よりグラウンド・ワンのすべてのタスクフォースにお伝えいたします。","ENG":"The City Management alerting all TASKFORCEs of Ground One.","TWN":"城市管理局向所有特遣勢力發佈通報。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_111010","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"현재, 3-3 봉쇄 구획 내에 있는 특수 개체 니블의 등급 정보가 상향 갱신 되었습니다.","JPN":"現在、3-3封鎖区画内にいる特殊個体ニブルのランク情報が上方修正されました。","ENG":"Currently, the Grade information for the special entity Nibble within the blockaded block 3-3 has been elevated.","TWN":"目前，3-3隔離區內的特殊個體[蠶食]的等級資訊已被上調。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_111010","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"토벌 보수는 정책에 따라 현재의 다섯 배로 증액. 새로운 대응 메뉴얼을 배포합니다.","JPN":"討伐報酬はポリシーに従って現在の5倍に増額。新しい対応マニュアルをお送りいたします。","ENG":"The bounty for extermination has been increased fivefold in accordance with the policy. A new response manual has been distributed.","TWN":"根據相關政策，討伐報酬提高至目前的五倍。即日起發步全新的應對手冊。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_111010","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"현 시간부로 그라운드 원 전체는 비상 경계 구역으로 지정됩니다.","JPN":"現時点からグラウンド・ワン全体を非常警戒エリアに指定します。","ENG":"As of now, all of Ground One is designated as an emergency alert zone.","TWN":"自即刻起，整個地面區域被劃定為緊急警戒區。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"도시 내 모든 안전 기관은 시민들이 침식체와의 접촉을 피할 수 있도록 대피에 협조 바랍니다.","JPN":"都市内の全ての安全機関は市民が侵食体と接触しないよう避難に協力してください。","ENG":"All safety institutions in the city are asked to cooperate in evacuating citizens to avoid contact with C.O.s.","TWN":"所有安全機構務必協助市民避免接觸侵蝕體並進行疏散。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"…솔로베- 그만 일어나야지.","JPN":"……ソロベー起きて。","ENG":"...Solovey. You have to wake up.","TWN":"……蘇羅薇，起來吧。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"집으로 돌아갈 시간이야.","JPN":"家に帰る時間よ。","ENG":"It's time to return home.","TWN":"是時候回家了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};